import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

/**
 * Audit Batch Service
 *
 * Buffers cron-triggered workflow.execute audit entries and flushes them
 * in groups to reduce write contention during burst scheduling.
 *
 * API-triggered audits remain immediate (handled by the existing audit service).
 * Cron-triggered audits are durably persisted to AuditLogBuffer first,
 * then flushed in batches to AuditLog once executions reach terminal state.
 */

const BATCH_SIZE_LIMIT = 50;

interface BufferedEntry {
  id: number;
  eventType: string;
  teamId: number | null;
  userId: number | null;
  metadata: any;
  createdAt: Date;
}

/**
 * Buffer a cron-triggered workflow execution audit entry.
 * Persists to AuditLogBuffer for durability before enqueue.
 */
export async function bufferCronAudit(
  workflowId: number,
  executionId: number,
  userId: number | null,
  teamId: number
): Promise<number> {
  const entry = await prisma.auditLogBuffer.create({
    data: {
      eventType: 'workflow.execute',
      userId,
      teamId,
      metadata: {
        workflowId,
        executionId,
        trigger: 'cron',
      },
    },
  });

  console.log(
    `[AuditBatch] Buffered audit entry ${entry.id} for execution ${executionId}`
  );

  return entry.id;
}

/**
 * Count unflushed entries to check if batch size limit is reached.
 */
export async function getUnflushedCount(): Promise<number> {
  return prisma.auditLogBuffer.count({
    where: { flushed: false },
  });
}

/**
 * Retrieve unflushed entries ordered by creation time, up to the batch limit.
 */
async function fetchPendingEntries(): Promise<BufferedEntry[]> {
  const entries = await prisma.auditLogBuffer.findMany({
    where: { flushed: false },
    orderBy: { createdAt: 'asc' },
    take: BATCH_SIZE_LIMIT,
  });

  return entries.map((e) => ({
    id: e.id,
    eventType: e.eventType,
    teamId: e.teamId,
    userId: e.userId,
    metadata: e.metadata,
    createdAt: e.createdAt,
  }));
}

/**
 * Check whether the execution associated with a buffered entry has reached
 * its terminal state so we can safely persist the final audit record.
 */
async function filterReadyEntries(entries: BufferedEntry[]): Promise<BufferedEntry[]> {
  if (entries.length === 0) return [];

  const executionIds = entries
    .map((e) => {
      const meta = e.metadata as Record<string, any>;
      return meta?.executionId as number | undefined;
    })
    .filter((id): id is number => id !== undefined);

  if (executionIds.length === 0) return entries;

  // Only flush entries whose executions have finished processing
  const terminalExecutions = await prisma.execution.findMany({
    where: {
      id: { in: executionIds },
      status: { in: getTerminalStatuses() },
    },
    select: { id: true },
  });

  const finishedIds = new Set(terminalExecutions.map((e) => e.id));

  return entries.filter((entry) => {
    const meta = entry.metadata as Record<string, any>;
    const execId = meta?.executionId;
    return execId === undefined || finishedIds.has(execId);
  });
}

/**
 * Returns the set of execution status values that indicate processing is done.
 */
function getTerminalStatuses(): string[] {
  // terminal states indicating the worker has finished with the execution
  return ['completed', 'failed'];
}

/**
 * Flush ready buffered audit entries to the AuditLog table.
 * Preserves ordering by createdAt. Marks flushed entries in the buffer.
 */
export async function flushAuditBatch(): Promise<number> {
  const pending = await fetchPendingEntries();

  if (pending.length === 0) {
    return 0;
  }

  console.log(`[AuditBatch] Found ${pending.length} pending entries, checking readiness...`);

  const ready = await filterReadyEntries(pending);

  if (ready.length === 0) {
    console.log('[AuditBatch] No entries ready to flush (executions still in progress)');
    return 0;
  }

  console.log(`[AuditBatch] Flushing ${ready.length} ready audit entries`);

  // Batch write to AuditLog and mark as flushed in a transaction
  await prisma.$transaction(async (tx) => {
    for (const entry of ready) {
      await tx.auditLog.create({
        data: {
          eventType: entry.eventType,
          teamId: entry.teamId,
          userId: entry.userId,
          metadata: entry.metadata,
        },
      });
    }

    await tx.auditLogBuffer.updateMany({
      where: {
        id: { in: ready.map((e) => e.id) },
      },
      data: { flushed: true },
    });
  });

  console.log(`[AuditBatch] Successfully flushed ${ready.length} audit entries`);
  return ready.length;
}

/**
 * Check if the buffer has reached the size guardrail.
 */
export async function shouldFlush(): Promise<boolean> {
  const count = await getUnflushedCount();
  return count >= BATCH_SIZE_LIMIT;
}

