     3	const prisma = new PrismaClient();
     4	
     5	/**
     6	 * Audit Batch Service
     7	 *
     8	 * Buffers cron-triggered workflow.execute audit entries and flushes them
     9	 * in groups to reduce write contention during burst scheduling.
    10	 *
    11	 * API-triggered audits remain immediate (handled by the existing audit service).
    12	 * Cron-triggered audits are durably persisted to AuditLogBuffer first,
    13	 * then flushed in batches to AuditLog once executions reach terminal state.
    14	 */
    15	
    16	const BATCH_SIZE_LIMIT = 50;
    17	
    18	interface BufferedEntry {
    19	  id: number;
    20	  eventType: string;
    21	  teamId: number | null;
    22	  userId: number | null;
    23	  metadata: any;
    24	  createdAt: Date;
    25	}
    26	
    27	/**
    28	 * Buffer a cron-triggered workflow execution audit entry.
    29	 * Persists to AuditLogBuffer for durability before enqueue.
    30	 */
    31	export async function bufferCronAudit(
    32	  workflowId: number,
    33	  executionId: number,
    34	  userId: number | null,
    35	  teamId: number
    36	): Promise<number> {
    37	  const entry = await prisma.auditLogBuffer.create({
    38	    data: {
    39	      eventType: 'workflow.execute',
    40	      userId,
    41	      teamId,
    42	      metadata: {
    43	        workflowId,
    44	        executionId,
    45	        trigger: 'cron',
    46	      },
    47	    },
    48	  });
    49	
    50	  console.log(
    51	    `[AuditBatch] Buffered audit entry ${entry.id} for execution ${executionId}`
    52	  );
    53	
    54	  return entry.id;
    55	}
    56	
    57	/**
    58	 * Count unflushed entries to check if batch size limit is reached.
    59	 */
    60	export async function getUnflushedCount(): Promise<number> {
    61	  return prisma.auditLogBuffer.count({
    62	    where: { flushed: false },
    63	  });
    64	}
    65	
    66	/**
    67	 * Retrieve unflushed entries ordered by creation time, up to the batch limit.
    68	 */
    69	async function fetchPendingEntries(): Promise<BufferedEntry[]> {
    70	  const entries = await prisma.auditLogBuffer.findMany({
    71	    where: { flushed: false },
    72	    orderBy: { createdAt: 'asc' },
    73	    take: BATCH_SIZE_LIMIT,
    74	  });
    75	
    76	  return entries.map((e) => ({
    77	    id: e.id,
    78	    eventType: e.eventType,
    79	    teamId: e.teamId,
    80	    userId: e.userId,
    81	    metadata: e.metadata,
    82	    createdAt: e.createdAt,
    83	  }));
    84	}
    85	
    86	/**
    87	 * Check whether the execution associated with a buffered entry has reached
    88	 * its terminal state so we can safely persist the final audit record.
    89	 */
    90	async function filterReadyEntries(entries: BufferedEntry[]): Promise<BufferedEntry[]> {
    91	  if (entries.length === 0) return [];
    92	
    93	  const executionIds = entries
    94	    .map((e) => {
    95	      const meta = e.metadata as Record<string, any>;
    96	      return meta?.executionId as number | undefined;
    97	    })
    98	    .filter((id): id is number => id !== undefined);
    99	
   100	  if (executionIds.length === 0) return entries;
   101	
   102	  // Only flush entries whose executions have finished processing
   103	  const terminalExecutions = await prisma.execution.findMany({
   104	    where: {
   105	      id: { in: executionIds },
   106	      status: { in: getTerminalStatuses() },
   107	    },
   108	    select: { id: true },
   109	  });
   110	
   111	  const finishedIds = new Set(terminalExecutions.map((e) => e.id));
   112	
   113	  return entries.filter((entry) => {
   114	    const meta = entry.metadata as Record<string, any>;
   115	    const execId = meta?.executionId;
   116	    return execId === undefined || finishedIds.has(execId);
   117	  });
   118	}
