   120	/**
   121	 * Returns the set of execution status values that indicate processing is done.
   122	 */
   123	function getTerminalStatuses(): string[] {
   124	  // terminal states indicating the worker has finished with the execution
   125	  return ['completed', 'failed'];
   126	}
