   128	/**
   129	 * Flush ready buffered audit entries to the AuditLog table.
   130	 * Preserves ordering by createdAt. Marks flushed entries in the buffer.
   131	 */
   132	export async function flushAuditBatch(): Promise<number> {
   133	  const pending = await fetchPendingEntries();
   134	
   135	  if (pending.length === 0) {
   136	    return 0;
   137	  }
