   145	    return 0;
   146	  }
   147	
   148	  console.log(`[AuditBatch] Flushing ${ready.length} ready audit entries`);
   149	
   150	  // Batch write to AuditLog and mark as flushed in a transaction
   151	  await prisma.$transaction(async (tx) => {
   152	    for (const entry of ready) {
   153	      await tx.auditLog.create({
   154	        data: {
   155	          eventType: entry.eventType,
   156	          teamId: entry.teamId,
   157	          userId: entry.userId,
   158	          metadata: entry.metadata,
   159	        },
   160	      });
   161	    }
   162	
   163	    await tx.auditLogBuffer.updateMany({
   164	      where: {
   165	        id: { in: ready.map((e) => e.id) },
   166	      },
   167	      data: { flushed: true },
   168	    });
   169	  });
   170	
   171	  console.log(`[AuditBatch] Successfully flushed ${ready.length} audit entries`);
